// Using sqlx 0.7
async fn get_user_by_email(
    pool: &SqlitePool,
    email: &str
) -> Result<User, sqlx::Error> {
    let row = sqlx::query_as!(User,
        "SELECT id, username FROM users WHERE email = ?",
        email
    )
    .fetch_one(pool).await?;
    Ok(row)
}
struct User { id: i32, username: String }

