// Corrected version
async fn get_user_by_email(
    pool: &SqlitePool,
    email: &str
) -> Result<Option<User>, sqlx::Error> {
    match sqlx::query_as!(User, "SELECT id, username FROM users WHERE email = ?", email)
        .fetch_one(pool).await { 
        Ok(row) => Ok(Some(row)),
        Err(sqlx::Error::RowNotFound) => Ok(None),
        Err(e) => Err(e),
    }
}
struct User { id: i32, username: String }

// Using diesel
fn get_user_by_email(pool: &PgConnection, email: &str) -> Result<Option<User>, diesel::result::Error> {
    use schema::users;
    let user = users::table.filter(users::email.eq(email)).first::<User>(pool);
    match user { Ok(u) => Ok(Some(u)), Err(diesel::NotFound) => Ok(None), _ => user }  
}

